    featureImage:
      "https://bahaiworld.bahai.org/wp-content/uploads/1936/04/2371743-master.jpg",
    featureImageAlt: "‘Abdu’l-Bahá with a group of Bahá’ís beneath the Eiffel Tower in Paris in 1913",
    addedOn: "2026-05-13",
